// Ported from Projector Power Control.txt — individual projector power on
const projector = global.get('projector');
const devices = global.get('devices');
const modeState = global.get('modeState');

const name = msg.payload.projector;  // 'left', 'right', or 'rear'
const proj = devices.projectors[name];

if (!proj) {
    node.error(`[powerOnProjector] Unknown projector name: "${name}"`, msg);
    return null;
}

(async () => {
    try {
        console.log(`[powerOnProjector] Powering on ${name} (${proj.ip})`);
        const success = await projector.powerOn(proj.ip);
        if (success) modeState.projectorPower[name] = true;
        console.log(`[powerOnProjector] ${name} result: ${success}`);
        msg.payload = { success, projector: name, action: 'powerOn' };
        node.send(msg);
    } catch (err) {
        node.error(`[powerOnProjector] ${err.message}`, msg);
    }
})();

return null;

