// Ported from Projector Power Control.txt — PowerAllOn
//
// IMPORTANT: The 60-second delay before firing the rear projector is intentional
// and must not be removed. It matches Timer.CallAfter(60, ...) in the original
// Q-SYS Lua and prevents simultaneous inrush current across all three lamp/laser
// units at startup. Left + right fire concurrently; rear fires after the delay.
const projector = global.get('projector');
const devices = global.get('devices');
const modeState = global.get('modeState');

const { left, right, rear } = devices.projectors;

(async () => {
    try {
        console.log('[powerAllOn] Firing left + right concurrently');
        await Promise.all([
            projector.powerOn(left.ip).then(() => { modeState.projectorPower.left = true; }),
            projector.powerOn(right.ip).then(() => { modeState.projectorPower.right = true; }),
        ]);
        console.log('[powerAllOn] Left + right started. Waiting 60s before rear (intentional stagger — do not remove)');

        await new Promise(resolve => setTimeout(resolve, 60000));

        console.log('[powerAllOn] Firing rear projector');
        await projector.powerOn(rear.ip);
        modeState.projectorPower.rear = true;

        console.log('[powerAllOn] All projectors started');
        msg.payload = { success: true, action: 'powerAllOn' };
        node.send(msg);
    } catch (err) {
        node.error('[powerAllOn] ' + err.message, msg);
    }
})();

return null;

// Ported from Projector Power Control.txt — PowerAllOff
// All three fire concurrently with no stagger — matches original Lua (power off has no delay).
const projector = global.get('projector');
const devices = global.get('devices');
const modeState = global.get('modeState');

const { left, right, rear } = devices.projectors;

(async () => {
    try {
        console.log('[powerAllOff] Powering off all projectors concurrently');
        await Promise.all([
            projector.powerOff(left.ip).then(() => { modeState.projectorPower.left = false; }),
            projector.powerOff(right.ip).then(() => { modeState.projectorPower.right = false; }),
            projector.powerOff(rear.ip).then(() => { modeState.projectorPower.rear = false; }),
        ]);
        console.log('[powerAllOff] All projectors shut down');
        msg.payload = { success: true, action: 'powerAllOff' };
        node.send(msg);
    } catch (err) {
        node.error('[powerAllOff] ' + err.message, msg);
    }
})();

return null;
